/** BigFishBon(b, level) — level = Spelunk[11][b]. Fully resolved, no unread inputs. */
export function bigFishBon(b, level) {
  const row = BIG_FISH[b];
  if (!row) throw new Error(`BigFishBon(${b}): no BIG_FISH row`);
  const lvl = Number(level ?? 0);
  return (lvl / (100 + lvl)) * row.coeff;
}
/** BigFishCost(b, level). */
export function bigFishCost(b, level) {
  const row = BIG_FISH[b];
  if (!row) throw new Error(`BigFishCost(${b}): no BIG_FISH row`);
  return Math.pow(1.15, Number(level ?? 0)) * Math.pow(10.01, row.costExp);
}

/** ShopUpgVisible(b, prereqLevel) — prereqLevel = Spelunk[5][SPELUNK_SHOP[b].prereqIdx]. */
export function shopUpgVisible(b, prereqLevel) {
  return b === 0 || Number(prereqLevel ?? -1) >= 0;
}
/** ShopUpgBonus(b, level, 1) — the e==1 arm (see header; the ONLY arm transcribed). */
export function shopUpgBonusRaw(b, level) {
  const row = SPELUNK_SHOP[b];
  if (!row) throw new Error(`ShopUpgBonus(${b}): no SPELUNK_SHOP row`);
  return row.coeff * Math.max(0, Number(level ?? 0));
}

