/** ChapterBonus(b, e, pagesRead, arbitraryCode5) — pagesRead = Spelunk[8][4*b+e];
 *  arbitraryCode5(mode,b,c,level) = the same curve evaluator used elsewhere in this repo
 *  (see bonuses/util.mjs::arbitraryCode5, imported by bonuses/talents.mjs). Artifact scaling
 *  (field4==1 in the raw table) never appears in the transcribed rows above (all false) — no
 *  chapter/slot currently uses it, so `artifactBonus35` is accepted but only applied if a future
 *  patch adds a `true` row. */
export function chapterBonus(b, e, pagesRead, arbitraryCode5Fn, artifactBonus35 = 0) {
  const row = (SPELUNK_CHAPTERS[b] ?? [])[e];
  if (!row) throw new Error(`ChapterBonus(${b},${e}): no SPELUNK_CHAPTERS row`);
  const scale = row.artifactScaled ? 1 + Number(artifactBonus35 ?? 0) / 100 : 1;
  return scale * arbitraryCode5Fn(row.mode, row.curveB, row.curveC, Number(pagesRead ?? 0));
}

/** StaminaBarWidth(totalStamina) — verbatim, capped at 364px. */
export function staminaBarWidth(totalStamina) {
  const s = Math.max(1, Number(totalStamina ?? 0));
  return Math.min(364, Math.ceil(75 + 5 * (Math.log(s) / Math.LN2) + 10 * (Math.log(s) / Math.LN10) + Math.min(20, s / 8)));
}
